#!/usr/bin/env node
/**
 * Scans blocks/ and writes blocks-catalog.json at the repo root.
 * This file is what every consuming site checks before building a new
 * block, and what CI checks to catch silent duplication. It's committed
 * to the repo (so it's served as a normal static file at
 * https://main--fedlibs--{org}.aem.live/blocks-catalog.json) and
 * regenerated by CI on every push to main — never hand-edited.
 */
const fs = require('fs');
const path = require('path');

const BLOCKS_DIR = path.join(__dirname, '..', 'blocks');
const OUTPUT = path.join(__dirname, '..', 'blocks-catalog.json');

function readDescription(blockDir, blockName) {
  // Optional: a block can ship a README.md whose first line becomes its
  // catalog description, so authors get useful info without a separate
  // registry to maintain.
  const readmePath = path.join(blockDir, 'README.md');
  if (fs.existsSync(readmePath)) {
    const firstLine = fs.readFileSync(readmePath, 'utf8').split('\n').find((l) => l.trim());
    if (firstLine) return firstLine.replace(/^#+\s*/, '').trim();
  }
  return `${blockName} block`;
}

function generateCatalog() {
  const blockNames = fs.readdirSync(BLOCKS_DIR, { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => entry.name)
    .filter((name) => fs.existsSync(path.join(BLOCKS_DIR, name, `${name}.js`)));

  const catalog = {
    generatedAt: new Date().toISOString(),
    blocks: blockNames.sort().map((name) => ({
      name,
      description: readDescription(path.join(BLOCKS_DIR, name), name),
    })),
  };

  fs.writeFileSync(OUTPUT, `${JSON.stringify(catalog, null, 2)}\n`);
  // eslint-disable-next-line no-console
  console.log(`Wrote ${catalog.blocks.length} blocks to blocks-catalog.json`);
}

generateCatalog();
